import{_ as s,o as a,c as e,Q as n}from"./chunks/framework.6a72df8e.js";const D=JSON.parse('{"title":"修复/重装MS Store","description":"","frontmatter":{"title":"修复/重装MS Store","date":"2022-05-17T11:34:38.000Z","tags":["记录问题"],"published":true,"hideInList":false,"feature":null,"isTop":false},"headers":[],"relativePath":"src/杂项/修复&重装MS Store.md","lastUpdated":1700455155000}'),l={name:"src/杂项/修复&重装MS Store.md"},o=n(`<p>昨天在下载Ubuntu on windows 时，一直提示安装失败，然后我把Microsoft Store给卸载了...之后费了好大劲才装回来。</p><ol start="0"><li><p><strong>使用管理员身份运行PowerShell</strong></p></li><li><p><strong>删除原来的微软Store</strong></p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#FFCB6B;">get-appxpackage</span><span style="color:#BABED8;"> </span><span style="color:#BABED8;">*</span><span style="color:#C3E88D;">store</span><span style="color:#BABED8;">*</span><span style="color:#BABED8;"> </span><span style="color:#89DDFF;">|</span><span style="color:#BABED8;"> </span><span style="color:#FFCB6B;">remove-Appxpackage</span></span>
<span class="line"></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></li><li><p><strong>获取包的全名</strong></p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#FFCB6B;">Get-AppxPackage</span><span style="color:#BABED8;"> </span><span style="color:#C3E88D;">-allusers</span><span style="color:#BABED8;"> </span><span style="color:#89DDFF;">|</span><span style="color:#BABED8;"> </span><span style="color:#FFCB6B;">Select</span><span style="color:#BABED8;"> </span><span style="color:#C3E88D;">Name,</span><span style="color:#BABED8;"> </span><span style="color:#C3E88D;">PackageFullName</span><span style="color:#BABED8;"> </span><span style="color:#89DDFF;">|</span><span style="color:#BABED8;"> select-string </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">WindowsStore</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></li></ol><p>执行完上边的指令之后，我们会得到以下的输出 @{Name=Microsoft.WindowsStore; PackageFullName=<span style="color:red;">Microsoft.WindowsStore_22204.1401.3.0_x64__8wekyb3d8bbwe</span>}</p><p>我们需要把上面红色的文字复制下来（<strong>注意：请以个人电脑上的实际输出为准！</strong>），这就是我们需要的包全名。</p><ol start="3"><li><strong>安装</strong><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#FFCB6B;">add-appxpackage</span><span style="color:#BABED8;"> </span><span style="color:#C3E88D;">-register</span><span style="color:#BABED8;"> </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">C:\\Program Files\\WindowsApps\\&lt;包全名&gt;\\AppxManifest.xml</span><span style="color:#89DDFF;">&quot;</span><span style="color:#BABED8;"> </span><span style="color:#C3E88D;">-disabledevelopmentmode</span></span>
<span class="line"></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></li></ol><p>把&lt;包全名&gt;替换成第2步复制的文本即可。</p><ol start="4"><li><strong>结束</strong> 等待一会儿之后就可以重新打开Microsoft Store了。</li></ol>`,7),p=[o];function t(r,c,i,d,y,B){return a(),e("div",null,p)}const g=s(l,[["render",t]]);export{D as __pageData,g as default};
